B.T3=new A.K("Introducci\xf3n","\xdaltima actualizaci\xf3n: Julio de 2026\nPerfectGest I ofrece control claro de los datos conforme a Google Play y la LGPD. La app es local-first.")
B.TT=new A.K("Resumen","Datos de clientes y financieros no se env\xedan autom\xe1ticamente a servidores PerfectGest. Solo salen del tel\xe9fono si usted comparte PDF, backups exportados, PNG/vCard de la tarjeta o muestra un QR con contactos profesionales.")
B.RQ=new A.K("1. Datos de gesti\xf3n (local)","Almacenados en SQLite en el dispositivo: clientes, presupuestos comerciales, presupuestos fiscales y c\xf3digos fiscales, caja, \xf3rdenes de servicio, datos de empresa (incluido logotipo), copia de la tarjeta, recordatorios fiscales.\n\nC\xf3mo eliminar\n\n- En la app: Ajustes \u2192 Datos en este dispositivo \u2192 Eliminar todos los datos\n- Android: Ajustes \u2192 Aplicaciones \u2192 PerfectGest I \u2192 Almacenamiento \u2192 Borrar datos\n- Desinstalar la app\n\nAviso: sin copia externa, no hay recuperaci\xf3n \u2014 no guardamos copias en nuestros servidores.\n\nBackups compartidos: elim\xednelos manualmente donde los guard\xf3.")
B.SD=new A.K("2. Firebase / telemetr\xeda","Metadatos an\xf3nimos de instalaci\xf3n y m\xe9tricas de uso (elegibilidad de suscripci\xf3n / antiabuso; primer guardado de tarjeta). No alojamos contenido de la tarjeta ni el logotipo en servidores.\n\nCorreo: suporte@perfectgestdev.com \u2014 Asunto: Solicitud de Eliminaci\xf3n de Datos T\xe9cnicos")
B.UF=new A.K("3. Notificaciones locales","Se cancelan al desinstalar o borrar los datos de la app.")
B.Ud=new A.K("4. Plazos","Datos locales: inmediato. Telemetr\xeda Firebase: hasta 15 d\xedas h\xe1biles tras la solicitud por correo.")
B.a1x=s([B.T3,B.TT,B.RQ,B.SD,B.UF,B.Ud],t.h)
