B.x2=s(["\u092a\u0939\u093f\u0932\u094b \u0938\u0924\u094d\u0930","\u0926\u094b\u0938\u094d\u0930\u094b \u0938\u0924\u094d\u0930","\u0924\u0947\u0938\u094d\u0930\u094b \u0938\u0924\u094d\u0930","\u091a\u094c\u0925\u094b \u0938\u0924\u094d\u0930"],t.s)
B.a29=s(["\u092a\u0939\u0932\u0940 \u0924\u093f\u092e\u093e\u0939\u0940","\u0926\u0942\u0938\u0930\u0940 \u0924\u093f\u092e\u093e\u0939\u0940","\u0924\u0940\u0938\u0930\u0940 \u0924\u093f\u092e\u093e\u0939\u0940","\u091a\u094c\u0925\u0940 \u0924\u093f\u092e\u093e\u0939\u0940"],t.s)
B.x3=s(["D","L","M","X","J","V","S"],t.s)
B.TJ=new A.K("Introdu\xe7\xe3o","\xdaltima actualizaci\xf3n: Julio de 2026")
B.Tf=new A.K("\xbfQu\xe9 es PerfectGest I?","App de gesti\xf3n en el tel\xe9fono, con datos locales (SQLite). No hay \xabcuenta en la nube\xbb PerfectGest para clientes, presupuestos o caja.")
B.TY=new A.K("\xbfFunciona sin internet?","S\xed, uso diario offline-first. Servicios Google opcionales (Analytics, Remote Config, Firestore m\xednimo de elegibilidad) pueden usar red cuando est\xe1n activos.")
B.TC=new A.K("\xbfPuedo usar la app sin suscripci\xf3n?","S\xed, para explorar (navegar pantallas y consultar la interfaz). Las operaciones (crear clientes, presupuestos comerciales o fiscales, caja; generar PDF de gesti\xf3n; restaurar backup cifrado; y dem\xe1s acciones condicionadas) requieren Plan Pro. Al intentar una operaci\xf3n sin suscripci\xf3n aparece un aviso con el plan (referencia R$ 9,90/mes; precio en Google Play) y Suscribirse o Continuar explorando los recursos de la aplicaci\xf3n.")
B.TZ=new A.K("\xbfC\xf3mo funciona el Plan Pro?","Suscripci\xf3n mensual o anual en Google Play: clientes, presupuestos, caja y PDF sin l\xedmite pr\xe1ctico; restauraci\xf3n de backup cifrado; tarjeta interactiva (vCard, QR, vista previa). Gestionar en Ajustes \u2192 Suscripci\xf3n Google Play.")
B.U9=new A.K("\xbfD\xf3nde gestiono la suscripci\xf3n?","Ajustes \u2192 Suscripci\xf3n Google Play. Cancelaci\xf3n: Play Store \u2192 Pagos y suscripciones.")
B.Uc=new A.K("\xbfQu\xe9 es la pesta\xf1a Presup./NF-e/NFS-e?","Presupuesto fiscal local (productos y servicios, c\xf3digos NCM/CFOP/LC 116, consulta/registro, PDF del presupuesto). Con estado Aprobado, puede generar un PDF gu\xeda NF con datos t\xe9cnicos y enlaces de portales oficiales. No emite NF-e ni NFS-e electr\xf3nica ante la autoridad fiscal.")
B.UJ=new A.K("\xbfQu\xe9 es la tarjeta de visita digital?","En Empresa, edita datos profesionales (no clientes ni caja). Compartir tarjeta genera PNG en la hoja de compartir. Tras la primera tarjeta, sin Plan Pro queda en modo est\xe1tico (puede compartir el PNG); con Pro, edita y usa funciones avanzadas solo en la app (vCard, QR, vista previa interactiva) \u2014 sin p\xe1gina web alojada por PerfectGest.\n\nClientes y datos financieros protegidos en el tel\xe9fono; no se env\xedan autom\xe1ticamente a servidores.")
B.U5=new A.K("\xbfEst\xe1n protegidos mis datos de clientes y financieros?","S\xed. Solo salen si usted comparte PDF, PNG/vCard/QR de la tarjeta o backup exportado (cifrado recomendado en Pro). Incluye presupuestos fiscales locales.")
B.Ug=new A.K("Recordatorios fiscales, calendario, \xfaltimos registros, notificaciones, anuncios, Crashlytics, idiomas?","Recordatorios locales informativos; calendario semanal en Empresa; atajos en inicio; solo notificaciones locales; sin anuncios; sin Crashlytics; PT / EN / ES.")
B.RG=new A.K("Privacidad, eliminaci\xf3n, sugerencias?","Ajustes \u2192 Ayuda y soporte para enlaces legales. Borrar datos: Ajustes \u2192 Datos en este dispositivo. Sugerencias: pesta\xf1a Empresa \u2192 suporte@perfectgestdev.com.")
